<script>

let androidIndex = 1; // start from 1 (next after first visible)

function loadMoreAndroid() {
  let container = document.getElementById("androidVideos");
  let videos = container.querySelectorAll(".video");

  // 🔁 Reset if reached end
  if (androidIndex >= videos.length) {
    // hide all first
    videos.forEach(v => v.style.display = "none");

    // show first again
    videos[0].style.display = "block";

    androidIndex = 1;
    return;
  }

  // show next video
  videos[androidIndex].style.display = "block";

  // scroll to it
  videos[androidIndex].scrollIntoView({
    behavior: "smooth",
    inline: "end"
  });

  androidIndex++;
}
  function hideAll(className) {
  var items = document.getElementsByClassName(className);
  for (var i = 0; i < items.length; i++) {
    items[i].style.display = "none";
  }
}
